const orderJsonKeys = (jsonObj) => {
  const ordered = {};
  Object.keys(jsonObj).sort().forEach(key => {
    ordered[key] = jsonObj[key];
  });
  return ordered;
}

const inputJson = $input.item.json;
const keys = Object.keys(inputJson);

// Check if file returned with content
if (keys.includes("content")) {
  const origWorkflow = JSON.parse(Buffer.from(inputJson.content, 'base64').toString());
  const n8nWorkflow = $('Execute Workflow Trigger').first().json;

  const orderedOriginal = orderJsonKeys(origWorkflow);
  const orderedActual = orderJsonKeys(n8nWorkflow);

  inputJson.file_sha = inputJson.sha;

  if (JSON.stringify(orderedOriginal) === JSON.stringify(orderedActual)) {
    inputJson.github_status = "same";
  } else {
    inputJson.github_status = "different";
    inputJson.n8n_data_stringy = JSON.stringify(orderedActual, null, 2);
  }
  inputJson.content_decoded = orderedOriginal;

} else if (keys.includes("data")) {
  const origWorkflow = JSON.parse(inputJson.data);
  const n8nWorkflow = $('Execute Workflow Trigger').first().json;

  const orderedOriginal = orderJsonKeys(origWorkflow);
  const orderedActual = orderJsonKeys(n8nWorkflow);

  inputJson.file_sha = inputJson.sha;

  if (JSON.stringify(orderedOriginal) === JSON.stringify(orderedActual)) {
    inputJson.github_status = "same";
  } else {
    inputJson.github_status = "different";
    inputJson.n8n_data_stringy = JSON.stringify(orderedActual, null, 2);
  }
  inputJson.content_decoded = orderedOriginal;

} else {
  const n8nWorkflow = $('Execute Workflow Trigger').first().json;
  const orderedActual = orderJsonKeys(n8nWorkflow);

  inputJson.file_sha = null;
  inputJson.github_status = "new";
  inputJson.n8n_data_stringy = JSON.stringify(orderedActual, null, 2);
}

return { json: inputJson };

// Accumulate failed workflow names across loop iterations using staticData
const staticData = $getWorkflowStaticData('global');
if (!Array.isArray(staticData.failedFlows)) {
  staticData.failedFlows = [];
}

const failedId   = $('Loop Over Items').item.json.id   ?? 'Unknown ID';
const failedName = $('Loop Over Items').item.json.name ?? 'Unknown Workflow';
staticData.failedFlows.push(`${failedName} (${failedId})`);

return [{ json: { failedId, failedName } }];

const staticData = $getWorkflowStaticData('global');
const totalCount = $('Filter: Exclude archived').all().length;
const failed = Array.isArray(staticData.failedFlows) ? staticData.failedFlows : [];
const dateStr = new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

// Build Adaptive Card for Teams
const bodyBlocks = [
  {
    type: 'TextBlock',
    text: `✅ Backup completed — ${totalCount} workflows processed.`,
    wrap: true,
    size: 'Medium',
    weight: 'Bolder',
    color: 'Good'
  }
];

if (failed.length > 0) {
  bodyBlocks.push({ type: 'TextBlock', text: `❌ Failed (${failed.length}):`, wrap: true, weight: 'Bolder', color: 'Attention' });
  bodyBlocks.push({ type: 'TextBlock', text: failed.join('\n'), wrap: true, color: 'Attention' });
}

const card = {
  type: 'AdaptiveCard',
  '$schema': 'http://adaptivecards.io/schemas/adaptive-card.json',
  version: '1.4',
  body: bodyBlocks
};

// Build HTML email body
const statusColor = failed.length > 0 ? '#c0392b' : '#27ae60';
const statusIcon  = failed.length > 0 ? '⚠️' : '✅';
const statusText  = failed.length > 0
  ? `Completed with ${failed.length} failure${failed.length > 1 ? 's' : ''}`
  : 'Completed successfully';

let failureRows = '';
if (failed.length > 0) {
  failureRows = `
    <tr>
      <td colspan="2" style="padding:16px 24px 4px;font-family:Arial,sans-serif;font-size:13px;font-weight:bold;color:#c0392b;">❌ Failed Workflows</td>
    </tr>
    ${failed.map(f => `
    <tr>
      <td colspan="2" style="padding:2px 24px 2px 36px;font-family:Arial,sans-serif;font-size:13px;color:#555;">• ${f}</td>
    </tr>`).join('')}
  `;
}

const htmlBody = `
<!DOCTYPE html>
<html>
<body style="margin:0;padding:0;background:#f4f4f4;">
  <table width="100%" cellpadding="0" cellspacing="0" style="background:#f4f4f4;padding:32px 0;">
    <tr>
      <td align="center">
        <table width="560" cellpadding="0" cellspacing="0" style="background:#ffffff;border-radius:8px;box-shadow:0 2px 8px rgba(0,0,0,0.08);overflow:hidden;">
          <tr>
            <td colspan="2" style="background:${statusColor};padding:20px 24px;">
              <span style="font-family:Arial,sans-serif;font-size:18px;font-weight:bold;color:#ffffff;">${statusIcon} n8n Workflow Backup</span>
            </td>
          </tr>
          <tr>
            <td colspan="2" style="padding:16px 24px 8px;font-family:Arial,sans-serif;font-size:12px;color:#888;border-bottom:1px solid #eeeeee;">${dateStr}</td>
          </tr>
          <tr>
            <td style="padding:16px 24px;font-family:Arial,sans-serif;font-size:13px;color:#555;width:50%;">Status</td>
            <td style="padding:16px 24px;font-family:Arial,sans-serif;font-size:13px;font-weight:bold;color:${statusColor};">${statusText}</td>
          </tr>
          <tr style="background:#f9f9f9;">
            <td style="padding:12px 24px;font-family:Arial,sans-serif;font-size:13px;color:#555;">Workflows processed</td>
            <td style="padding:12px 24px;font-family:Arial,sans-serif;font-size:13px;font-weight:bold;color:#333;">${totalCount}</td>
          </tr>
          <tr>
            <td style="padding:12px 24px;font-family:Arial,sans-serif;font-size:13px;color:#555;">Successful</td>
            <td style="padding:12px 24px;font-family:Arial,sans-serif;font-size:13px;font-weight:bold;color:#27ae60;">${totalCount - failed.length}</td>
          </tr>
          ${failed.length > 0 ? `
          <tr style="background:#f9f9f9;">
            <td style="padding:12px 24px;font-family:Arial,sans-serif;font-size:13px;color:#555;">Failed</td>
            <td style="padding:12px 24px;font-family:Arial,sans-serif;font-size:13px;font-weight:bold;color:#c0392b;">${failed.length}</td>
          </tr>` : ''}
          ${failureRows}
          <tr>
            <td colspan="2" style="padding:16px 24px;background:#f4f4f4;font-family:Arial,sans-serif;font-size:11px;color:#aaa;border-top:1px solid #eeeeee;">Sent by n8n Workflow Backup · Automated message</td>
          </tr>
        </table>
      </td>
    </tr>
  </table>
</body>
</html>`;

staticData.failedFlows = [];

return [{ json: { cardJson: JSON.stringify(card), htmlBody, dateStr, totalCount, failedCount: failed.length } }];

